 1	import React, { FC } from 'react';
 2	
 3	import { HyperConverged } from '@kubevirt-utils/hooks/useHyperConvergeConfiguration';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { modelToGroupVersionKind, ProjectModel } from '@kubevirt-utils/models';
 6	import { K8sResourceCommon, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 7	import AutomaticImagesDownload from '@overview/SettingsTab/ClusterTab/components/GeneralSettings/TemplatesAndImagesManagement/components/AutomaticImagesDownload/AutomaticImagesDownload';
 8	import BootableVolumeProjectSection from '@overview/SettingsTab/ClusterTab/components/GeneralSettings/TemplatesAndImagesManagement/components/BootableVolumeProjectSection/BootableVolumeProjectSection';
 9	import TemplatesProjectSection from '@overview/SettingsTab/ClusterTab/components/GeneralSettings/TemplatesAndImagesManagement/components/TemplatesProjectSection/TemplatesProjectSection';
10	import ExpandSection from '@overview/SettingsTab/ExpandSection/ExpandSection';
11	import { Stack, StackItem } from '@patternfly/react-core';
12	
13	type TemplatesAndImagesManagementProps = {
14	  hyperConvergeConfiguration: [hyperConvergeConfig: HyperConverged, loaded: boolean, error: any];
15	  newBadge?: boolean;
16	};
17	
18	const TemplatesAndImagesManagement: FC<TemplatesAndImagesManagementProps> = ({
19	  hyperConvergeConfiguration,
20	  newBadge,
21	}) => {
22	  const { t } = useKubevirtTranslation();
23	  const projectsData = useK8sWatchResource<K8sResourceCommon[]>({
24	    groupVersionKind: modelToGroupVersionKind(ProjectModel),
25	    isList: true,
26	  });
27	
28	  return (
29	    <ExpandSection toggleText={t('Templates and images management')}>
30	      <Stack hasGutter>
31	        <StackItem>
32	          <AutomaticImagesDownload
33	            hyperConvergeConfiguration={hyperConvergeConfiguration}
34	            newBadge={newBadge}
35	          />
36	        </StackItem>
37	        <StackItem isFilled>
38	          <BootableVolumeProjectSection
39	            hyperConvergeConfiguration={hyperConvergeConfiguration}
40	            projectsData={projectsData}
41	          />
42	        </StackItem>
43	        <StackItem isFilled>
44	          <TemplatesProjectSection
45	            hyperConvergeConfiguration={hyperConvergeConfiguration}
46	            projectsData={projectsData}
47	          />
48	        </StackItem>
49	      </Stack>
50	    </ExpandSection>
51	  );
52	};
53	
54	export default TemplatesAndImagesManagement;

